var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 이대로 있어도 되는 걸까?","JPN":"本当にこのままでいいのかな？","ENG":"Can we really do nothing?","TWN":"這樣真的沒關係嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이러고 있는 동안, 돌이킬 수 없는 일이 벌어지기라도 하면……","JPN":"こうしているうちに、取り返しのつかないことでも起きたら……","ENG":"What if something irreversible happens while we wait...","TWN":"萬一在這段時間發生什麼無法挽回的事……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미나야? 왜 그렇게 멍하니 있어?","JPN":"ミナさん？　どうしてそんなにボーっとしてるの？","ENG":"Mina? What are you spacing out about?","TWN":"米娜？你在發什麼呆？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"我……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안. 생각할 게 좀 있어서.","JPN":"ごめん。ちょっと考え事をしてた。","ENG":"Sorry. I just have a lot on my mind.","TWN":"抱歉，我在想事情。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"계속 마음에 걸리면 따로 선배를 찾으러 가도 돼.","JPN":"やっぱり気になるなら、別行動で先輩を探しに行ってもいいよ。","ENG":"If it bothers you that much, you can go find him on your own.","TWN":"你要是這麼擔心的話，就自己去找前輩吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아까 회의하기 전부터 계속 안절부절하고 있었잖아.","JPN":"会議の前からずっとソワソワしてたでしょ。","ENG":"You've been antsy all day, even before the briefing.","TWN":"從開會前你就一直坐立不安的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님께는 내가 적당히 둘러대 줄 테니까. 네 소대장으로서.","JPN":"副社長には私が適当に言い訳しておくから。一応、今はあなたの小隊長だし。","ENG":"I'll think of some excuse to give to the Vice President. It's the least I can do as your commander.","TWN":"副總那邊我會隨便找個說法呼攏過去的，這是我這個小隊長唯一能為你做的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고마워. 나도 그러고 싶긴 하지만…….","JPN":"ありがとう。私もそうしたいけど……","ENG":"Thanks. I appreciate it. But as much as I'd love to take up your offer...","TWN":"謝謝你，我也很想立刻衝去找人……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님 말이 맞아. 단서도 없이 어디부터 가야 할지…….","JPN":"副社長の言うとおりだよ。手がかりもないし、行く当てもないから……","ENG":"The Vice President is right. I can't just go sniffing around without a single lead...","TWN":"但副總說的沒錯，人海茫茫要從何找起呢……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누구지? 딱히 연락 올 데는 없는데?","JPN":"あれ、電話？　誰だろう？","ENG":"Huh? Who could that be? I'm not expecting any calls right now.","TWN":"誰啊？應該沒人會打來找我啊？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실례합니다. 혹시 유미나 학생인가요?","JPN":"もしもし。ヤナギ・ミナさんのお電話でお間違いないでしょうか？","ENG":"Excuse me. Is this Mina?","TWN":"不好意思，請問是劉米娜同學嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학생회장……?","JPN":"生徒会長……？","ENG":"Student President?","TWN":"學生會長……？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 무슨 일이야? 내 번호는 또 어떻게 알았고?","JPN":"急にどうしたの？　私の電話番号どうしてわかったの？","ENG":"What's up? How did you even get my number?","TWN":"有什麼事嗎？你怎麼會知道我的電話？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"편입할 때 제출했던 서류를 참고했어요.","JPN":"編入時の書類を確認しました。","ENG":"I referred to your transfer documentation.","TWN":"我查了你入學時交的資料。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"소식은 전해 들었어요. 동료 분께서 실종되셨다죠.","JPN":"話は聞きました。同僚の方が行方不明になったそうですね。","ENG":"I heard the news. A colleague of yours went missing.","TWN":"我聽說了，你的夥伴失蹤了對吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아. 경찰이 수색 중이긴 한데 아직 특별한 단서가 없나 봐.","JPN":"うん。警察が捜索しているけど、まだこれといった手がかりはないみたい。","ENG":"Yeah. The police are searching, but it sounds like they haven't found any leads yet.","TWN":"沒錯，警察正在找人，但好像還沒有發現什麼線索。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうでしたか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실은 이번 다이브 훈련 중 발생한 사고를 두고 아카데미도 전방위로 조사를 진행 중입니다.","JPN":"実は今回のダイブ訓練中に発生した\\n事故について、アカデミーも総力を挙げて調査を進行中です。","ENG":"The Academy has also been conducting an investigation of the accident during the recent dive training.","TWN":"是這樣的，針對這次躍入訓練中發生的事件，學院正在全面進行調查。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그런데 그 과정에서 조금 납득하기 어려운 점들이 계속해서 드러나고 있어요.","JPN":"そして、その過程で不自然な点が次々と明らかになっています。","ENG":"And throughout the investigation, we’ve kept finding things that cannot be explained.","TWN":"在調查過程中，我們發現到一些可疑的地方。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"납득하기 어려운 점이라니?","JPN":"不自然な点って？","ENG":"Such as?","TWN":"可疑的地方？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"가령, 다이브 실전 훈련의 승인 경위겠군요.","JPN":"例えば、ダイブ実戦訓練の承認経緯です。","ENG":"Such as how the dive training itself came to be.","TWN":"譬如說，允許躍入實戰訓練。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미 학생들은 대부분 다이브를 경험한 적이 없어요.","JPN":"アカデミーの生徒たちはほとんどダイブを経験したことがありません。","ENG":"Most of the students at the Academy had no prior diving experience, you see.","TWN":"學院大部分的學生都沒有躍入的經驗。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그들이 단체로 다이브를 하면 그림자와 같은 고위 침식체가 출몰할 확률이 아주 높아요.","JPN":"そんな生徒たちが団体でダイブをすれば、\\nシャドウのような高位侵食体が出没する確率が非常に高くなります。","ENG":"A mass dive with so many inexperienced individuals would greatly increase the chance of powerful C.O.s appearing. Shadows, for instance.","TWN":"當他們團體進行躍入時，會有很高的機率出現像是暗影那樣的高級侵蝕體。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"충분히 대책을 마련한다고 해도 위험에 처할 수 있다는 건 미나 학생도 직접 겪었죠?","JPN":"十分な対策を講じたとしても\\n危険にさらされることがあると、ミナさんも直接経験したと思います。","ENG":"I'm sure you know from personal experience that one cannot prepare for every possible risk.","TWN":"雖然已經做好充分的準備，但還是有可能落入危險當中，這種經驗你應該也有過吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장은 훈련에 찬성해서 협력한 거 아니었어?","JPN":"会長は訓練に賛成して協力したんじゃないの？","ENG":"I thought you joined the dive training because you were in favor of it.","TWN":"會長不是也同意訓練嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"총학생회는 줄곧 실전 훈련에 반대했어요. 지원 부대만 믿고 학생들을 이면세계로 보낼 수는 없었으니까요.","JPN":"生徒会はずっと実戦訓練に反対していました。\\n支援部隊だけを頼りにして、生徒たちを裏世界に送るわけにはいかないからです。","ENG":"Actually, the Student Council has always been opposed to the training. We simply couldn't send students off to the Counterside while complacently relying on reinforcements to come.","TWN":"學生會一直是反對實戰訓練的，怎麼可能單憑支援部隊就把學生送到異界呢！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 정작 교무 회의에서 훈련을 강행하자던 선생님들도, 지금은 왜 이런 계획에 찬성했는지 영문을 모르겠다고 하시더군요.","JPN":"しかし、職員会議で訓練強行に賛成していた先生たちも、\\n今はなぜ自分があの計画に賛成したのかわからないと言っていました。","ENG":"But apparently the faculty, who supported the training during the staff meeting, are now saying they have no idea why they agreed to it.","TWN":"就連當初那些在教務會議上贊成強制訓練的老師，現在也不明白當初為何會贊成這樣的計畫。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 훈련……. 알렌 선생님이 입안했다고 들었어.","JPN":"あの訓練……アレン先生が立案したと聞いたよ。","ENG":"That dive training... I heard Mr. Birmingham was the one who suggested it.","TWN":"那個訓練……我聽說是艾倫老師提議的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당사자한테 직접 물어 보면 되지 않아?","JPN":"当事者に直接聞けばいいんじゃない？","ENG":"Why don't you ask him yourself?","TWN":"為何不直接去問當事人呢？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금은 그럴 수 없어요.","JPN":"今はそれができないのです。","ENG":"I'm afraid that's out of the question right now.","TWN":"我們現在無法詢問當事人。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"훈련 입안자인 알렌 선생님과 중요 참고인인 레이 학생 모두, 훈련 이후 실종된 상태거든요.","JPN":"訓練立案者のアレン先生と重要参考人のレイさんどちらも、訓練後に行方不明となっています。","ENG":"Both Allen Birmingham, who suggested the training, and Ray, a key witness, have gone missing.","TWN":"因為訓練計畫的提案人和重要證人雷伊同學，訓練後便下落不明。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실종?","JPN":"行方不明？","ENG":"Missing?","TWN":"下落不明？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 학교에 모습을 비추지 않는 것은 물론, 연락처도 모두 불통이에요.","JPN":"はい。学校に来ていないのはもちろん、連絡先も全て繋がりません。","ENG":"I'm afraid so. Not only are they absent from the campus, but they won't even answer our calls.","TWN":"是的，他們沒出現在學校，也完全聯絡不上人。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우연이라기에는 아주 공교로운 상황이죠.","JPN":"偶然というにはできすぎた状況です。","ENG":"It's far too peculiar to be a mere coincidence.","TWN":"說是巧合的話未免也太湊巧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……어째서 나한테 그런 정보를 알려 주는 거야?","JPN":"……どうして私にそんな情報を教えてくれるの？","ENG":"And why are you telling me all this?","TWN":"……你為什麼要跟我說這些？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"밖으로 새어 나가면 회장이 곤란해지는 거 아냐?","JPN":"こういう話が外部に漏れたら、困るのは会長じゃない？","ENG":"Wouldn't you rather keep this on the down low, given your position?","TWN":"萬一我把消息洩漏出去，會長會很麻煩吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 학생이 꼭 알아야 할 이야기를 들었기 때문이에요.","JPN":"ミナさんが必ず知っておくべき話を聞いたからです。","ENG":"It's because I heard something you must know.","TWN":"因為有件事你必須要知道。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"꼭 알아야 할 이야기……?","JPN":"必ず知っておくべき話って……？","ENG":"Something I must know?","TWN":"我必須要知道……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지난 주말, 근신 처분을 받은 나이엘 학생이 몰래 기숙사를 벗어난 일이 있었습니다.","JPN":"先週末、謹慎処分を受けたナイエルさんがこっそり寮を抜け出したことがありました。","ENG":"Last weekend, Naielle snuck out of her dormitory after being grounded.","TWN":"上週發生一件事，原本被罰禁足的奈爾偷跑出宿舍。"},"stage":{"bg":"CITY_CENTER2","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"증언에 따르면 레이 학생에게 누가 위인지 다시 한 번 가르쳐 줄 생각이었다더군요.","JPN":"証言によると、レイさんに誰が上なのか、もう一度教えてあげるつもりだったそうです。","ENG":"According to her testimony, she was hoping to put Ray back in his place.","TWN":"根據目擊者表示，他說要去教訓雷伊，讓他少囂張。"},"stage":{"bg":"CITY_CENTER2","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실전 훈련 당시 건방지게 자기를 구하려 했다는 이유로 말이에요.","JPN":"実戦訓練の時、生意気にも自分を助けようとしたからといった理由でした。","ENG":"Apparently, she found it insulting that he tried to save her during training.","TWN":"起因是在實戰訓練當時，雷伊很囂張地說要救他。"},"stage":{"bg":"CITY_CENTER2","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석……. 조금은 나아질 줄 알았더니…….","JPN":"あいつ……少しはマシな人間になったと思ったのに……","ENG":"Oh, geez... I thought she'd learned her lesson...","TWN":"那傢伙……我還以為他現在有收斂一點……"},"stage":{"bg":"CITY_CENTER2","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 시비 걸 기회를 잡기 위해 레이 학생을 미행하던 중에 목격했다고 해요.","JPN":"そして、ケンカを売る機会を探るためにレイさんを尾行する途中、目撃したそうです。","ENG":"And while she was shadowing him, looking for a chance to pick a fight, she saw him...","TWN":"然後在跟蹤雷伊同學想要伺機找他麻煩時，"},"stage":{"bg":"CITY_CENTER2","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"레이 학생이 그 주시윤이라는 분과 만나는 모습을.","JPN":"レイさんがそのアキヤマ・シリュウという方と話しているのを。","ENG":"She saw Ray with that colleague of yours, Joo Shiyoon.","TWN":"發現雷伊同學與那個叫周時雲的人見面。"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 정말이야?!","JPN":"え？　本当！？","ENG":"What? For real?!","TWN":"什麼？！是真的嗎？"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 목격 장소는 시내 중심가 빌딩의 헬리포트였다는군요.","JPN":"はい。目撃場所は市内の中心街にあるビルのヘリポートだそうです。","ENG":"Yes. She saw them at a building downtown, at its heliport.","TWN":"是的，就在市中心的直升機場。"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"거긴……. 내가 선배를 마지막으로 봤던 곳이야.","JPN":"そこは……私が先輩と最後に会った場所だ。","ENG":"That's... the last place I saw Shiyoon.","TWN":"那裡……就是我最後一次看到前輩的地方！"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"역시 그랬군요.","JPN":"やはりそうでしたか。","ENG":"Ah, so it all adds up.","TWN":"果然是這樣。"},"stage":{"bg":"MAINSTREAM_6100014","bgm":"UI_BASE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"두 사람이 잠시 대화를 나눈 뒤, 강한 섬광과 함께 폭발이 발생했다고 해요.","JPN":"二人がしばらく会話した後、強い閃光とともに爆発が起こったそうです。","ENG":"After their conversation, the heliport was engulfed in an explosion.","TWN":"他們兩個短暫談話後，就伴隨著強烈閃光發生大爆炸。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 학생은 폭발에 휘말려 정신을 잃는 바람에 그 이후 상황은 모른다더군요.","JPN":"ナイエルさんは爆発に巻き込まれて気を失ったせいで、その後の状況は知らないそうです。","ENG":"Naielle said that's the last she remembers, since the explosion knocked her unconscious.","TWN":"奈爾同學受到爆炸的波擊而失去意識，後來的事他就不知道了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"내가 언제 정신을 잃었다는 거야?!","JPN":"はあ！？　私がいつ気を失ったっていうわけ！？","ENG":"Who ever said I got knocked out?!","TWN":"你少胡說，我才不是失去意識！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"난 그냥 불필요한 자극을 받지 않게 감각 기관을 닫아 뒀을 뿐이라고!","JPN":"私は余計な刺激を受けないように感覚器官を閉じておいただけなの！","ENG":"I simply shut my sensory organs down to avoid any unnecessary stimulation!","TWN":"我只是為了避免受到不必要刺激，而暫時關閉感官功能而已！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"사람들은 그런 걸 보통 기절이라고 불러요.","JPN":"人々はそういうことを一般的に「気絶」と言います。","ENG":"Most people would call that getting knocked out.","TWN":"在醫學上通常稱這種現象為昏倒。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 그런 광경을 목격했다면, 무섭더라도 곧장 경찰이나 도시 관리국에 알렸어야죠.","JPN":"そして、そのような光景を目撃したのであれば、\\n怖くてもすぐに警察や都市管理局に知らせるべきでした。","ENG":"May I remind you, you should have informed the authorities of this immediately, no matter how scared you were.","TWN":"而且發生這種事，就算害怕也應該要報警或是通知城市管理局吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무, 무섭다니……!","JPN":"こ、怖いだなんて……！","ENG":"S-scared?!","TWN":"你…你說誰害怕…！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"웃기지 마! 애초에 나랑 잘 아는 사이도 아닌데 뭐하러 신경을 써?","JPN":"笑わせないで！　そもそも別に知り合いでもない人間に気をかける必要ないでしょ？","ENG":"Don’t make me laugh! Besides why would I give a hoot about him? I never knew him that well anyway!","TWN":"拜託！我跟那些人又不熟，管他們死活幹嘛！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"진심으로 하는 말인가요, 나이엘 학생?","JPN":"それは本気で言っていますか、ナイエルさん？","ENG":"Do you truly mean that, Naielle?","TWN":"奈爾同學，你這話是認真的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"힉……!","JPN":"ひぃ……！","ENG":"Eep...!","TWN":"唔……！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어쨌거나 근신 중 기숙사 이탈은 중대한 교칙 위반 행위예요.","JPN":"いずれにせよ、謹慎中に寮から離脱したことは重大な校則違反行為です。","ENG":"In any case, leaving your dormitory when you're grounded is a grave violation of regulations.","TWN":"不管怎麼樣，你無視禁足令離開宿舍就是違反校規。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 나이엘 학생을 데리고 가 주세요.","JPN":"イーディス、ナイエルさんを連れていってください。","ENG":"Edith, please escort Naielle back.","TWN":"把伊蒂絲和奈爾同學帶走。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음냐……. 지금은 더 자고 싶은데…….","JPN":"むにゃ……今はもっと寝てたいのに……","ENG":"Aw... I wanted to sleep a little more...","TWN":"哈……人家還想睡啦……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"부탁할게, 야누스…….","JPN":"頼むよ、ヤヌス……","ENG":"Please take care of this, Janus...","TWN":"雅努斯拜託啦……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"제 완벽한 변신 시스템에 불미스러운 문제를 일으켰던 분이시군요! 반갑습니다!","JPN":"私の完璧な変身システムに問題を起こした方ですね！　お会いできて嬉しいです！","ENG":"Ah, you're the one who caused this undesirable issue with my perfect transformation system! Nice to meet you!","TWN":"你不就是擾亂我完美變身系統的人嗎！你好！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"안내해 드리겠습니다. 따라 오시죠.","JPN":"ご案内いたします。ついてきてください。","ENG":"Please allow me to show you the way. Follow me.","TWN":"我來為你帶路，請跟我來！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐? 고철 주제에 누구더러……!","JPN":"はあ？　ポンコツのくせに誰に向かって……！","ENG":"What? You can't tell me what to do, you piece of junk!","TWN":"拜託！你不過就是塊廢鐵，那邊跟我五四三……！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 잠깐! 갑자기 플라즈마 소드는 왜 꺼내 드는 건데?","JPN":"ま、待ってよ！　何でいきなりプラズマソードを取り出すの？","ENG":"W-wait! What's with the plasma sword?","TWN":"喂！你沒事把離子刀拿出來幹嘛啦！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_03"},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"앗 따거! 따갑다고!!","JPN":"いたっ！　痛いって！！","ENG":"Ah, ouch! That stings!!","TWN":"噢！很刺欸！刺刺的啦！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이거 화풀이 하는 거지? 이디스 선배! 이 고철 좀 말려!","JPN":"これただの八つ当たりだよね？　イーディス先輩！　このポンコツを止めてよ！","ENG":"You're just taking your anger out on me, aren't you? Edith! Stop this piece of junk!","TWN":"你根本是在公報私仇吧！伊蒂絲前輩，你看他啦！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"아, 나이엘님. 그것은 심각한 오해입니다.","JPN":"あ、ナイエル様。それは深刻な誤解です。","ENG":"Oh, Ms. Naielle. I'm afraid there's been a grave misunderstanding.","TWN":"奈爾，這是個誤會。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_TOUCH"}}}},{"id":"L3_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"저는 인공지능입니다.","JPN":"私は人工知能です。","ENG":"I am an artificial intelligence, you see.","TWN":"我身為人工智慧，"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"그러므로 인간과 같이 특정한 감정에 휘둘려 불필요한 과잉대응을 하는 일은 불가능함을 알려드립니다.","JPN":"ですので、人間のように特定の感情に振り回されて不要な過剰対応をすることは不可能であることをお伝えします。","ENG":"Which means I am incapable of allowing emotions to prompt excessive use of force, unlike humans.","TWN":"不可能像人類一樣，陷入情緒當中就做出過於激動的行為。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"거짓말! 거짓말이야! 앗, 따거! 찌르지 마! 찌르지 말라고!!","JPN":"嘘！　嘘でしょ！　痛っ、刺さないで！　刺さないでってば！","ENG":"Liar! You're lying! Ah, ouch! Stop it! Stop poking me!!","TWN":"你騙人！我不聽我不聽～～！吼唷！你不要一直戳我啦！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……잠시 소란이 있었네요.","JPN":"……お騒がせしました。","ENG":"...Please excuse this brief commotion.","TWN":"……吵吵鬧鬧的真不好意思。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 이 두 사건 간에 저희가 모르는 어떤 연관성이 존재한다고 생각해요.","JPN":"私はこの2つの事件の間に私たちがまだ知らない、何らかの関連性があると思っています。","ENG":"I for one believe there's some sort of an unknown relation between these two incidents.","TWN":"我認為這兩件事應該有什麼關聯性。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서 지금부터 조사차 알렌 선생님의 자택을 방문할 예정이에요.","JPN":"ですので、今から調査のためにアレン先生のご自宅を訪問する予定です。","ENG":"And as such, I'm on my way to visit Mr. Birmingham's residence to investigate.","TWN":"所以我們現在正打算要去艾倫老師的家看看有沒有什麼線索。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"괜찮다면 합류하셔도 좋아요, 유미나 학생. 주소는 별도로 보내 드리죠.","JPN":"よろしければミナさんも合流していただいて構いません。住所は別途共有します。","ENG":"You're welcome to join me, if you'd like. I'll send you the address.","TWN":"方便的話，我們可以一起合作。地址我會另外傳給你。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 되겠어? 일단은 아카데미 내부의 일이잖아?","JPN":"本当にいいの？　一応アカデミー内部のことなのに？","ENG":"You sure about that? Isn't this an internal Academy affair?","TWN":"這樣沒問題嗎？這不是學院內部的事嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 그리고 유미나 학생도 저희 아카데미의 학생이에요.","JPN":"はい、そしてミナさんもアカデミーの生徒ですから。","ENG":"You're quite right. And it just so happens you're one of the Academy's students.","TWN":"是的，但你也是學院的學生。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……시윤 선배랑 레이 선배가 싸웠다고?","JPN":"……アキヤマ先輩とレイ先輩が戦ったって？","ENG":"So...","TWN":"……時雲前輩和雷伊前輩吵架？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말일까? 하지만 대체 왜……?","JPN":"本当かな？　でもいったいどうして……？","ENG":"Shiyoon and Ray fought each other? Could that be true?","TWN":"這是真的嗎？可是為什麼……？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭘 고민하고 있어. 단서 하나 없어서 끙끙거리고 있었는데 잘됐잖아.","JPN":"何を悩んでるの。全く手がかりがなくてモヤモヤしていたでしょ。よかったじゃない。","ENG":"But why...? Why are you hesitating?","TWN":"你在考慮什麼？你不是一直碎念找不到線索嗎？現在這樣不是正好？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어서 가. 주시윤 선배를 찾아야지.","JPN":"早く行って。アキヤマ先輩を見つけないと。","ENG":"This is perfect. Weren't you looking for Shiyoon anyway? You should get going.","TWN":"快去吧！去找周時雲前輩吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……갑자기 미안한데, 정찰하고 싶은 지역이 생겼어. 소대장.","JPN":"……急で申し訳ないけど、偵察したい地域があるんだ、小隊長。","ENG":"Sorry to ask you out of the blue, but there's an area I'd like to scout out... Commander.","TWN":"……小隊長抱歉，我突然要去調查一個地方。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"딱히 보수가 들어 올 만한 일감은 아니지만, 꼭 지금 가야 해.","JPN":"報酬が出る仕事ではないけど、今すぐ行かなきゃならない。","ENG":"It's not quite something worth money... but I really must get going.","TWN":"雖然不是會有高額報酬的工作，但我必須要去一趟！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐흠. 흥미로운 건의로군요. 유미나 소대원.","JPN":"ふーむ。それは中々興味深い案件ですね、ヤナギ・ミナ小隊員。","ENG":"Hmm... What an interesting proposition... Yoo Mina.","TWN":"呵呵～感覺很有意思呢！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장, 서둘러. 의뢰주가 지정한 좌표로 가려면 10분 내로 출발해야 돼.","JPN":"隊長、急いで。依頼主が指定した座標に行くには10分以内に出発しないと。","ENG":"We should hurry. We need to leave in 10 minutes if we want to reach the coordinates in time.","TWN":"隊長，沒時間了，我們必須在10分鐘內出發，才能抵達委託人指定的座標。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미안. 린. 잠깐 소대장직을 대신해 줘야 할 거 같아.","JPN":"ごめんね、リン。ちょっとだけ小隊長を代わってもらいたいの。","ENG":"Sorry, Lin. I think you'll have to sub in for me for now.","TWN":"曉琳抱歉，要麻煩你暫時代理小隊長的位置。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"난 여기 쓸데없이 죽을 상을 하고 있는 아가씨를 좀 도와 줘야 할 것 같거든.","JPN":"私はここで渋い顔をしている女の子をちょっと助けてあげないといけないの。","ENG":"I need to help a young lady who looks quite depressed for no reason at all.","TWN":"我必須幫幫這位這位滿臉愁容的小姐。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"서윤, 너……?","JPN":"シズカ……？","ENG":"You.. You're going to... help me?","TWN":"徐芸你……？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"알겠어. 임시 소대원에게 너무 정 붙이지만 마.","JPN":"了解。でも臨時小隊員だから、あまり親しくしすぎないようにね。","ENG":"Fine. I don't know what got into you, but I hope you don't get too attached to our temporary squadmate.","TWN":"好吧，但我勸你不要對小隊員太感情用事。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"소대장 자리 좋다는 게 뭐겠어. 작전 재량권은 이럴 때 써먹어야지.","JPN":"小隊長の権限はこういう時に使わないとね。","ENG":"It's good to be a Squad Commander. I have enough discretion in operations.","TWN":"當小隊長有什麼好處？不就是在這種時候可以發號施令嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 소대원의 건의를 받아들여서, 비정기 정찰을 수행하는 걸로. 어때?","JPN":"それじゃあ小隊員の意見を受け入れて、不定期偵察を遂行することにしよう。どう？","ENG":"Let's say I took up a squad member's recommendation and decided to launch a reconnaissance mission. How's that?","TWN":"那就接受小隊員的委託，進行非正式搜查吧！如何？"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……고마워.","JPN":"……ありがとう。","ENG":"...Thanks.","TWN":"……謝謝你。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배를 찾으면 내가 아포칼립스에서 컵라면이라도 쏠게.","JPN":"先輩を見つけたらアポカリプスで焼きそばパンでも奢るね。","ENG":"If we find Shiyoon, I'll buy you cup noodles at Apocalypse or something.","TWN":"找到前輩後我請你去阿波卡利斯吃泡麵加蛋！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나 제법 잘 끓이거든.","JPN":"コロッケパンでもいいよ。","ENG":"I can make one mean cup of noodles.","TWN":"我可是煮泡麵高手！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄, 컵라면 정도로 만족하기엔 난 좀 비싼 여자라.","JPN":"さあ、それぐらいで満足するかなー？","ENG":"Well, I'm not sure if that's going to cut it.","TWN":"這樣喔，一碗泡麵就想打發我，我還真是廉價呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그래? 하지만 당장은 보답할 게 별로 없는데……","JPN":"そ、そう？　でも今は他にお返しできるようなものがないんだけど……","ENG":"R-really? But I don't have much to pay you with right now...","TWN":"是…是喔？可是我沒什麼東西可以報答你……"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"됐어. 이 빚은 나중에 이자까지 쳐서 받아갈 테니까.","JPN":"いいよ。この貸しは今度利子まで計算してしっかり返してもらうから。","ENG":"No worries. I'm going to call in this favor later... with interest.","TWN":"沒關係，這筆帳之後我會連本帶利地向你討回來。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"가자, 유미나 소대원. 정찰은 신속 정확이 생명이잖아.","JPN":"行こう、ミナ小隊員。偵察は迅速かつ正確が命でしょう。","ENG":"Let's get going then. Speed and precision are of the essence when it comes to reconnaissance, after all.","TWN":"走吧，劉米娜小隊員！搜查的重點就是要快狠準！"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알겠어.","JPN":"わ、わかった。","ENG":"G-got it.","TWN":"喔…好。"},"stage":{"bg":"CORRIDOR_02","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};